import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const p=JSON.parse('{"title":"Insertion Colis","description":"","frontmatter":{"title":"Insertion Colis"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-mail/index.md","filePath":"docs/fr/advertisers/sponsored-mail/index.md"}'),r={name:"docs/fr/advertisers/sponsored-mail/index.md"};function n(l,e,o,d,c,u){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="insertion-colis-sponsored-mail" tabindex="-1">Insertion Colis (Sponsored Mail) <a class="header-anchor" href="#insertion-colis-sponsored-mail" aria-label="Permalink to &quot;Insertion Colis (Sponsored Mail)&quot;">​</a></h1><p>Glissez votre offre (flyer, carte, échantillon) à l&#39;intérieur des colis d&#39;e-commerçants soigneusement sélectionnés — et touchez vos clients au moment de l&#39;unboxing.</p><hr><h2 id="comment-ca-marche" tabindex="-1">Comment ça marche ? <a class="header-anchor" href="#comment-ca-marche" aria-label="Permalink to &quot;Comment ça marche ?&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Sélectionnez vos distributeurs</h3><p>Parcourez le réseau de +250 e-commerçants partenaires. Filtrez par secteur, panier moyen, géographie et profil B2B/B2C pour construire votre plan média ciblé.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Créez vos supports</h3><p>Concevez votre flyer en respectant les <a href="./design-guide/print-specs">spécifications techniques</a> et les <a href="./design-guide/legal">mentions légales</a>. Intégrez le QR Code dynamique fourni par getinside — c&#39;est votre outil de tracking.</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Livraison en entrepôt</h3><p>Vous expédiez vos supports (ou confiez l&#39;impression à notre Studio). getinside gère la logistique et l&#39;acheminement directement aux entrepôts des distributeurs.</p></div></div><div class="gi-step"><div class="gi-step-num done">4</div><div class="gi-step-body"><h3>Pilotez en temps réel</h3><p>Suivez les scans QR et les volumes distribués depuis votre tableau de bord. Reporting hebdomadaire mis à jour par chaque distributeur.</p></div></div><hr><h2 id="pourquoi-ce-levier-est-incontournable" tabindex="-1">Pourquoi ce levier est incontournable <a class="header-anchor" href="#pourquoi-ce-levier-est-incontournable" aria-label="Permalink to &quot;Pourquoi ce levier est incontournable&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>📦 100% d&#39;Ouverture</strong><p>Le seul média physique avec un taux de prise en main absolu. Le client attend son colis avec impatience — votre flyer est vu, tenu en main, dans un moment d&#39;attention maximale.</p></div><div class="gi-value-card"><strong>🎯 Ciblage Comportemental</strong><p>Vous touchez des acheteurs réels, qualifiés par leurs habitudes de consommation — pas des internautes anonymes. Secteur, panier moyen, géographie : le ciblage est précis et mesurable.</p></div><div class="gi-value-card"><strong>🛡️ Cookie-less &amp; RGPD</strong><p>Canal 100% offline : aucune dépendance aux cookies tiers, aucune restriction RGPD sur le ciblage. Un levier durable face à la saturation et à la hausse des coûts du digital.</p></div></div><hr><h2 id="ciblage-audiences" tabindex="-1">Ciblage &amp; Audiences <a class="header-anchor" href="#ciblage-audiences" aria-label="Permalink to &quot;Ciblage &amp; Audiences&quot;">​</a></h2><p>Sélectionnez vos distributeurs selon quatre critères :</p><table tabindex="0"><thead><tr><th style="text-align:left;">Critère</th><th style="text-align:left;">Options disponibles</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Univers produit</strong></td><td style="text-align:left;">Beauté, Food, Tech, Maison, Sport, Mode, Bien-être…</td></tr><tr><td style="text-align:left;"><strong>Panier moyen (AOV)</strong></td><td style="text-align:left;">High-end, Mass Market, Discounter, Économe</td></tr><tr><td style="text-align:left;"><strong>Profil acheteur</strong></td><td style="text-align:left;">B2C (particuliers) ou B2B (professionnels)</td></tr><tr><td style="text-align:left;"><strong>Géographie</strong></td><td style="text-align:left;">France, Belgique, Espagne, Allemagne…</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Exclusivité sectorielle garantie</p><p>Votre offre est toujours insérée chez un e-commerçant <strong>non concurrent</strong>. Et dans un même colis, deux offres concurrentes ne peuvent jamais coexister.</p></div><hr><h2 id="formats" tabindex="-1">Formats <a class="header-anchor" href="#formats" aria-label="Permalink to &quot;Formats&quot;">​</a></h2><h3 id="flyers-cartes" tabindex="-1">Flyers &amp; Cartes <a class="header-anchor" href="#flyers-cartes" aria-label="Permalink to &quot;Flyers &amp; Cartes&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Dimensions finies</th><th style="text-align:left;">Usage recommandé</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>A5</strong></td><td style="text-align:left;">148 × 210 mm</td><td style="text-align:left;">Format standard — idéal pour les offres détaillées</td></tr><tr><td style="text-align:left;"><strong>A6</strong></td><td style="text-align:left;">105 × 148 mm</td><td style="text-align:left;">Format compact — idéal pour les codes promo</td></tr><tr><td style="text-align:left;"><strong>Carte</strong></td><td style="text-align:left;">105 × 148 mm</td><td style="text-align:left;">Format carte cadeau ou fidélité</td></tr></tbody></table><h3 id="echantillons-sampling" tabindex="-1">Échantillons (Sampling) <a class="header-anchor" href="#echantillons-sampling" aria-label="Permalink to &quot;Échantillons (Sampling)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Poids max</th><th style="text-align:left;">Développé max</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>S</strong></td><td style="text-align:left;">15 g</td><td style="text-align:left;">15 cm</td></tr><tr><td style="text-align:left;"><strong>M</strong></td><td style="text-align:left;">100 g</td><td style="text-align:left;">30 cm</td></tr><tr><td style="text-align:left;"><strong>L</strong></td><td style="text-align:left;">450 g</td><td style="text-align:left;">40 cm</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Option Duo — Flyer + Échantillon</p><p>Un échantillon Format S peut être fixé sur un flyer A5/A6 via un point de colle fugitive (repositionnable). Réalisé par des Entreprises Adaptées (EA).</p></div><hr><h2 id="performances-roi" tabindex="-1">Performances &amp; ROI <a class="header-anchor" href="#performances-roi" aria-label="Permalink to &quot;Performances &amp; ROI&quot;">​</a></h2><p>Les benchmarks observés sur le réseau getinside :</p><table tabindex="0"><thead><tr><th style="text-align:left;">Indicateur</th><th style="text-align:left;">Benchmark réseau</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Taux de scan (CTR)</strong></td><td style="text-align:left;">1% à 10%</td></tr><tr><td style="text-align:left;"><strong>Taux de conversion post-scan (CVR)</strong></td><td style="text-align:left;">10% à 30%</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Maximiser le ROI</p><ul><li><strong>Valeur monétaire</strong> : <em>&quot;10€ offerts&quot;</em> convertit bien mieux que <em>&quot;-10%&quot;</em>. La valeur concrète est immédiatement perçue.</li><li><strong>QR Code + UTM</strong> : combinez le QR code getinside avec des paramètres UTM (<code>utm_source=getinside&amp;utm_medium=insertion-colis</code>) pour tracker les ventes dans Google Analytics.</li><li><strong>Code promo unique</strong> : ajoutez un code spécifique par distributeur pour l&#39;attribution offline.</li><li><strong>Durée de validité</strong> : prévoyez au moins 3 mois — les destinataires conservent souvent les flyers plusieurs semaines avant de les scanner.</li></ul></div><hr><h2 id="tarification" tabindex="-1">Tarification <a class="header-anchor" href="#tarification" aria-label="Permalink to &quot;Tarification&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Poste</th><th style="text-align:left;">Coût</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Accès à la plateforme</strong></td><td style="text-align:left;">Gratuit, sans abonnement</td></tr><tr><td style="text-align:left;"><strong>Frais de plateforme</strong></td><td style="text-align:left;">12% du budget média investi</td></tr><tr><td style="text-align:left;"><strong>Impression</strong> (optionnel)</td><td style="text-align:left;">Tarifs dégressifs en achat groupé — Made in France, certifié Imprim&#39;Vert</td></tr><tr><td style="text-align:left;"><strong>Studio Créatif</strong> (optionnel)</td><td style="text-align:left;">Forfait 550€ HT par campagne</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Pas d&#39;engagement minimum</p><p>Vous lancez votre première campagne quand vous voulez, avec le budget que vous choisissez. Les frais de plateforme ne s&#39;appliquent qu&#39;au budget réellement engagé.</p></div><hr><h2 id="pourquoi-passer-par-getinside" tabindex="-1">Pourquoi passer par getinside ? <a class="header-anchor" href="#pourquoi-passer-par-getinside" aria-label="Permalink to &quot;Pourquoi passer par getinside ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🌐 Réseau Exclusif</strong><p>+250 e-commerçants partenaires avec des audiences de niche souvent inaccessibles en direct. Un seul interlocuteur pour l&#39;ensemble du réseau.</p></div><div class="gi-value-card"><strong>🏭 Logistique Intégrée</strong><p>Impression Made in France (Imprim&#39;Vert, FSC), conditionnement et livraison en entrepôt gérés par getinside. Vous vous concentrez sur votre campagne.</p></div><div class="gi-value-card"><strong>📊 Pilotage Centralisé</strong><p>Un dashboard unique pour suivre les distributions (reporting hebdo) et les performances QR (scans en temps réel). Zéro email de coordination.</p></div></div><hr><h2 id="demarrer" tabindex="-1">Démarrer <a class="header-anchor" href="#demarrer" aria-label="Permalink to &quot;Démarrer&quot;">​</a></h2><p><strong>Prêt à lancer votre première campagne ?</strong></p><ul><li><a href="./design-guide/">📘 Guide de Conception</a> — Spécifications techniques, mentions légales, stratégie créative.</li><li><a href="https://app.getinside.media/" target="_blank">🚀 Créer une campagne</a> — Accédez à la plateforme directement.</li></ul><div class="info custom-block"><p class="custom-block-title">Besoin d&#39;aide ?</p><p>Notre Studio Créatif prend en charge la direction artistique et l&#39;exécution pour <strong>550€ HT</strong> par campagne. → <a href="/handbook/docs/fr/resources/studio.html">Contacter le Studio</a></p></div>',40)])])}const m=t(r,[["render",n]]);export{p as __pageData,m as default};
